function handleNavClick(e, url, icon, label) {
  // Don't intercept if modifier keys held (open in new tab etc)
  if (e.metaKey || e.ctrlKey || e.shiftKey) return;
  e.preventDefault();
  if (window.__apexNavTo) {
    window.__apexNavTo(url, icon, label);
  } else {
    window.location.href = url;
  }
}

export function renderNav(activePage) {
  // Inject CSS
  if (!document.getElementById('apex-nav-styles')) {
    const style = document.createElement('style');
    style.id = 'apex-nav-styles';
    style.textContent = NAV_CSS;
    document.head.appendChild(style);
  }

  // Build nav HTML
  const nav = document.createElement('nav');
  nav.className = 'apex-nav';
  nav.id = 'apexNav';

  let html = `<a class="apex-nav-logo" href="/dashboard/">
    <span class="apex-nav-logo-icon">✦</span>
    <span class="apex-nav-logo-text">MAGI</span>
  </a>
  <div class="apex-nav-scroll">`;

  for (const group of NAV_GROUPS) {
    html += `<div class="apex-nav-group-label">${group.label}</div>`;
    for (const item of group.items) {
      const isActive = activePage === item.id ? ' active' : '';
      html += `<a class="apex-nav-item${isActive}" href="${item.path}" data-nav-icon="${item.icon}" data-nav-label="${item.label}">
        <span class="apex-nav-item-icon">${item.icon}</span>
        <span class="apex-nav-item-label">${item.label}</span>
      </a>`;
    }
  }

  html += `</div>
  <div class="apex-nav-footer">
    <span style="font-size:14px;">✦</span>
    <span class="apex-nav-footer-text">MAGI v2.0</span>
  </div>`;

  nav.innerHTML = html;

  // Attach click handlers for page transitions
  nav.querySelectorAll('.apex-nav-item').forEach(item => {
    item.addEventListener('click', (e) => {
      handleNavClick(e, item.getAttribute('href'), item.dataset.navIcon, item.dataset.navLabel);
    });
  });

  // Logo also uses transitions
  const logoLink = nav.querySelector('.apex-nav-logo');
  if (logoLink) {
    logoLink.addEventListener('click', (e) => {
      handleNavClick(e, '/dashboard/', '⬡', 'Dashboard');
    });
  }

  // Create hamburger button
  const burger = document.createElement('button');
  burger.className = 'apex-nav-hamburger';
  burger.id = 'apexNavBurger';
  burger.innerHTML = '☰';
  burger.setAttribute('aria-label', 'Toggle navigation');

  // Create overlay
  const overlay = document.createElement('div');
  overlay.className = 'apex-nav-overlay';
  overlay.id = 'apexNavOverlay';

  // Inject into DOM
  const target = document.getElementById('nav');
  if (target) {
    target.appendChild(nav);
    target.appendChild(burger);
    target.appendChild(overlay);
  } else {
    document.body.prepend(overlay);
    document.body.prepend(nav);
    document.body.prepend(burger);
  }

  // Mobile toggle
  function toggleMobileNav() {
    const open = nav.classList.toggle('mobile-open');
    overlay.classList.toggle('show', open);
  }
  burger.addEventListener('click', toggleMobileNav);
  overlay.addEventListener('click', toggleMobileNav);

  return nav;
}

/**
 * AlphaClaw Apex — Page Transition System
 * ES Module: import { initTransitions, navTo } from '/shared/transitions.js';
 */

let _overlay = null;

export function initTransitions() {
  // Create overlay DOM if not present
  if (!document.getElementById('apex-transition')) {
    _overlay = document.createElement('div');
    _overlay.id = 'apex-transition';
    _overlay.innerHTML = `
      <span class="t-icon"></span>
      <span class="t-label"></span>
    `;
    document.body.appendChild(_overlay);
  } else {
    _overlay = document.getElementById('apex-transition');
  }

  // Fade in current page content on load
  requestAnimationFrame(() => {
    const pageContent = document.querySelector('.page-enter');
    if (pageContent) {
      // Small delay for the browser to paint the initial state
      requestAnimationFrame(() => {
        pageContent.classList.add('visible');
      });
    }
  });
}

export function navTo(url, icon, label) {
  if (!_overlay) {
    // Fallback if transitions not initialized
    window.location.href = url;
    return;
  }

  // 1. Fade out current page content
  const pageContent = document.querySelector('.page-enter');
  if (pageContent) {
    pageContent.classList.remove('visible');
  }

  // 2. Set icon and label text
  const iconEl = _overlay.querySelector('.t-icon');
  const labelEl = _overlay.querySelector('.t-label');
  if (iconEl) iconEl.textContent = icon || '✦';
  if (labelEl) labelEl.textContent = label || '';

  // 3. Show overlay
  _overlay.classList.add('active');
  _overlay.classList.remove('show-icon', 'show-label');

  // 4. After 200ms: show icon
  setTimeout(() => {
    _overlay.classList.add('show-icon');
  }, 200);

  // 5. After 500ms: show label
  setTimeout(() => {
    _overlay.classList.add('show-label');
  }, 500);

  // 6. After 1200ms: navigate
  setTimeout(() => {
    window.location.href = url;
  }, 1200);
}

// Register globally so nav.js can call it
window.__apexNavTo = navTo;

/**
 * AlphaClaw Apex — Animated CountUp
 * ES Module: import { initCountUp } from '/shared/countup.js';
 *
 * Usage: <span data-countup="1234">0</span>
 * Supports: integers, decimals (data-countup="99.5"), percentages (data-countup="87.3%")
 */

function easeOutQuart(t) {
  return 1 - Math.pow(1 - t, 4);
}

function animateValue(el, target, isPercent, decimals) {
  const duration = 800;
  const start = performance.now();

  function update(now) {
    const elapsed = now - start;
    const progress = Math.min(elapsed / duration, 1);
    const eased = easeOutQuart(progress);
    const current = eased * target;

    if (decimals > 0) {
      el.textContent = current.toFixed(decimals) + (isPercent ? '%' : '');
    } else {
      el.textContent = Math.round(current).toLocaleString() + (isPercent ? '%' : '');
    }

    if (progress < 1) {
      requestAnimationFrame(update);
    } else {
      // Ensure final value is exact
      if (decimals > 0) {
        el.textContent = target.toFixed(decimals) + (isPercent ? '%' : '');
      } else {
        el.textContent = Math.round(target).toLocaleString() + (isPercent ? '%' : '');
      }
    }
  }

  requestAnimationFrame(update);
}

function parseTarget(raw) {
  let isPercent = false;
  let str = raw.trim();

  if (str.endsWith('%')) {
    isPercent = true;
    str = str.slice(0, -1);
  }

  // Remove commas
  str = str.replace(/,/g, '');

  const value = parseFloat(str);
  if (isNaN(value)) return null;

  // Determine decimal places
  const dotIndex = str.indexOf('.');
  const decimals = dotIndex >= 0 ? str.length - dotIndex - 1 : 0;

  return { value, isPercent, decimals };
}

export function initCountUp() {
  const elements = document.querySelectorAll('[data-countup]');
  if (!elements.length) return;

  // Use IntersectionObserver to trigger when visible
  if ('IntersectionObserver' in window) {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const el = entry.target;
          const parsed = parseTarget(el.dataset.countup);
          if (parsed) {
            animateValue(el, parsed.value, parsed.isPercent, parsed.decimals);
          }
          observer.unobserve(el);
        }
      });
    }, { threshold: 0.1 });

    elements.forEach(el => observer.observe(el));
  } else {
    // Fallback: animate all immediately
    elements.forEach(el => {
      const parsed = parseTarget(el.dataset.countup);
      if (parsed) {
        animateValue(el, parsed.value, parsed.isPercent, parsed.decimals);
      }
    });
  }
}
